params.functionCall:
{
  "name": "classify_confirmation",
  "description": "ユーザーの返答を『肯定』『否定』『NO_RESULT』の3つに分類。DTMF(1:肯定 2:否定)を最優先し、STTの断片からも意図を汲み取ります。",
  "parameters": {
    "type": "object",
    "properties": {
      "intent": {
        "type": "string",
        "enum": [
          "肯定",
          "否定",
          "NO_RESULT"
        ],
        "description": "分類結果。1や『はい』の断片は『肯定』、2や『いいえ/ちがう』の断片は『否定』。"
      }
    },
    "required": ["intent"]
  }
}

params.script:
var res = $runner.getModuleResult("復唱_患者_生年月日");
$runner.setResult(res || "done");
var flowName = $runner.getCurrentFlowName();
var rid = $ivr.getRID();
var key = flowName + "." + rid;
$ivr.setObject(key, res || "done");
